129	bool ClassCommand::PrintClass(art::mirror::Object& object, const char* classname) {
130	    if (!object.IsClass())
131	        return false;
132	
133	    art::mirror::Class thiz = object;
134	    if (options.dump_all) {
135	        options.total_classes++;
136	        LOGI("[%" PRId64 "] " ANSI_COLOR_LIGHTYELLOW "0x%" PRIx64 "" ANSI_COLOR_LIGHTCYAN " %s\n" ANSI_COLOR_RESET,
137	                options.total_classes, thiz.Ptr(), thiz.PrettyDescriptor().c_str());
138	        if (options.show_flag) PrintPrettyClassContent(thiz, options);
139	    } else if (thiz.PrettyDescriptor() == classname) {
140	        PrintPrettyClassContent(thiz, options);
141	    }
142	
143	    return false;
144	}
