146	void ClassCommand::PrintPrettyClassContent(art::mirror::Class& clazz, ClassCommand::Options& options) {
147	    LOGI(ANSI_COLOR_LIGHTYELLOW "[0x%" PRIx64 "]\n" ANSI_COLOR_RESET, clazz.Ptr());
148	    art::mirror::Class super = clazz.GetSuperClass();
149	    art::mirror::IfTable& iftable = clazz.GetIfTable();
150	    int32_t ifcount = (iftable.Ptr() && iftable.IsValid()) ? iftable.Count() : 0;
151	    bool needEnd = false;
152	    if (super.Ptr()) {
153	        LOGI(ANSI_COLOR_LIGHTGREEN "%s" "class " ANSI_COLOR_RESET "%s" ANSI_COLOR_LIGHTGREEN " extends " ANSI_COLOR_RESET "%s" " {\n",
154	                art::PrettyClassAccessFlags(clazz.GetAccessFlags()).c_str(),
155	                clazz.PrettyDescriptor().c_str(), super.PrettyDescriptor().c_str());
156	    } else {
157	        LOGI(ANSI_COLOR_LIGHTGREEN "%s" "class " ANSI_COLOR_RESET "%s" " {\n",
158	                art::PrettyClassAccessFlags(clazz.GetAccessFlags()).c_str(),
159	                clazz.PrettyDescriptor().c_str());
160	    }
161	    if (ifcount > 0 && (options.show_flag & SHOW_IMPL)) {
162	        LOGI(ANSI_COLOR_LIGHTCYAN "  // Implements:\n" ANSI_COLOR_RESET);
163	        for (int i = 0; i < ifcount; ++i) {
164	            art::mirror::Class interface = iftable.GetInterface(i);
165	            try {
166	                LOGI("    %s\n", interface.PrettyDescriptor().c_str());
167	            } catch(InvalidAddressException& e) {
168	                LOGI("    java.lang.Class<0x%" PRIx64 ">\n", interface.Ptr());
169	            }
170	        }
171	        needEnd = true;
172	    }
173	    std::string format = PrintCommand::FormatSize(clazz.SizeOf());
174	    std::string format_nonenter = format;
175	    format.append("\n");
176	
177	    art::mirror::Class current = clazz;
178	    if (clazz.NumStaticFields() && (options.show_flag & SHOW_STATIC)) {
179	        if (needEnd) ENTER();
180	        LOGI(ANSI_COLOR_LIGHTCYAN "  // Class static fields:\n" ANSI_COLOR_RESET);
181	        needEnd = true;
182	    }
183	    std::vector<art::ArtField> fields;
184	    auto print_static_field = [&](art::ArtField& field) -> bool {
185	        fields.push_back(field);
186	        return false;
187	    };
188	    if ((options.show_flag & SHOW_STATIC)) {
189	        Android::ForeachStaticField(current, print_static_field);
190	        std::sort(fields.begin(), fields.end(), art::ArtField::Compare);
191	
192	        PrintCommand::Options print_options = {
193	            .format_hex = options.format_hex,
194	        };
195	
196	        for (auto& field : fields) {
197	            PrintCommand::PrintField(format_nonenter.c_str(), current, clazz, field, print_options);
198	        }
199	        fields.clear();
200	    }
201	
202	    if (clazz.NumInstanceFields() && (options.show_flag & SHOW_FIELD)) {
203	        if (needEnd) ENTER();
204	        LOGI(ANSI_COLOR_LIGHTCYAN "  // Object instance fields:\n" ANSI_COLOR_RESET);
205	        needEnd = true;
206	    }
207	    super = clazz;
208	    do {
209	        if (!(options.show_flag & SHOW_FIELD))
210	            break;
211	
212	        if (clazz != super) {
213	            if (needEnd) ENTER();
214	            LOGI(ANSI_COLOR_LIGHTCYAN "  // extends %s\n" ANSI_COLOR_RESET, super.PrettyDescriptor().c_str());
215	            needEnd = true;
216	        }
217	
218	        auto callback = [&](art::ArtField& field) -> bool {
219	            fields.push_back(field);
220	            return false;
221	        };
222	        Android::ForeachInstanceField(super, callback);
223	        std::sort(fields.begin(), fields.end(), art::ArtField::Compare);
224	        for (auto& field : fields) {
225	            LOGI(format.c_str(), field.offset(), art::PrettyFieldAccessFlags(field.access_flags()).c_str(),
226	                                 field.PrettyTypeDescriptor().c_str(), field.GetName());
227	        }
228	        fields.clear();
229	
230	        super = super.GetSuperClass();
231	    } while (super.Ptr());
232	
233	    if (clazz.NumMethods() && (options.show_flag & SHOW_METHOD)) {
234	        if (needEnd) ENTER();
235	        LOGI(ANSI_COLOR_LIGHTCYAN "  // Methods:\n" ANSI_COLOR_RESET);
236	        needEnd = true;
237	    }
238	    auto print_method = [](art::ArtMethod& method) -> bool {
239	        LOGI("    [0x%" PRIx64 "] " ANSI_COLOR_LIGHTGREEN "%s" ANSI_COLOR_RESET "%s\n",
240	                method.Ptr(), art::PrettyMethodAccessFlags(method.access_flags()).c_str(), method.ColorPrettyMethod().c_str());
241	        return false;
242	    };
243	    if ((options.show_flag & SHOW_METHOD)) Android::ForeachArtMethods(current, print_method);
244	
245	    LOGI("}\n");
246	}
