92	class Class : public Object {
93	public:
94	    Class(uint32_t v) : Object(v) {}
95	    Class(const Object& ref) : Object(ref) {}
96	    Class(const api::MemoryRef& ref) : Object(ref) {}
97	    Class(uint32_t v, Object* ref) : Object(v, ref) {}
98	    Class(uint32_t v, api::MemoryRef& ref) : Object(v, ref) {}
99	    Class(uint32_t v, api::MemoryRef* ref) : Object(v, ref) {}
100	
101	    inline bool operator==(Class& ref) { return Ptr() == ref.Ptr(); }
102	    inline bool operator!=(Class& ref) { return Ptr() != ref.Ptr(); }
103	    inline bool operator==(uint32_t v) { return Ptr() == v; }
104	    inline bool operator!=(uint32_t v) { return Ptr() != v; }
105	    inline bool operator==(const Class& ref) const { return Ptr() == ref.Ptr(); }
106	    inline bool operator!=(const Class& ref) const { return Ptr() != ref.Ptr(); }
107	    inline bool operator<(const Class& ref) const { return Ptr() < ref.Ptr(); }
108	    inline bool operator>(const Class& ref) const { return Ptr() > ref.Ptr(); }
109	
110	    struct Hash {
111	        std::size_t operator()(const Class& clazz) const {
112	            std::hash<uint32_t> vaddr_hasher;
113	            return vaddr_hasher(clazz.Ptr());
114	        }
115	    };
